const input = items[0].json;
let rawText = input.output || input.text || input.response || 
              (input.content?.parts?.[0]?.text) || (input.message?.content) || "";

try {
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error("Không tìm thấy JSON");
  const p = JSON.parse(jsonMatch[0]);
  return [{
    json: {
      category: p.category || null,
      sales_subcategory: (p.sales_subcategory || "consultation").toLowerCase().trim(),
      brand: (p.brand || "").toLowerCase().trim(),
      model_slug: (p.model_slug || "").toLowerCase().trim(),
      car_type: (p.car_type || "").toLowerCase().trim(),
      seat_min: p.seat_min ? Number(p.seat_min) : null,
      fuel: (p.fuel || "").toLowerCase().trim(),
      budget_max: p.budget_max ? Number(p.budget_max) : null,
      price_sort: (p.price_sort || "").toLowerCase().trim() || null,
      use_case: p.use_case || null,
      qa_intents: Array.isArray(p.qa_intents) ? p.qa_intents : [],
      compare_with_brand: (p.compare_with_brand || "").toLowerCase().trim(),
      compare_with_model: (p.compare_with_model || "").trim(),
      compare_target: (p.compare_target || "").toLowerCase().trim(),
      status: typeof p.status === "boolean" ? p.status : false
    }
  }];
} catch(e) {
  return [{ json: { category: "ERROR_FORMAT", raw_debug: rawText.substring(0,200), status: false }}];
}

// FILTER ENGINE + MARKDOWN TRIMMER + FAQ INTENT FILTER + COMPARISON + ROLLING PRICE CALC
// Paste vào n8n node: "Code in JavaScript" (sau Switch.SALES_LEAD)
const d = $input.first().json;
const base = 'https://raw.githubusercontent.com/Meeyana/thacoauto-lib/main/';

// === Entity từ Router ===
const brand = (d.brand || "").toLowerCase().trim();
const model_slug = (d.model_slug || "").toLowerCase().trim();
const car_type = (d.car_type || "").toLowerCase().trim();
const seat_min = d.seat_min ? Number(d.seat_min) : null;
const fuel = (d.fuel || "").toLowerCase().trim();
const budget_max = d.budget_max ? Number(d.budget_max) : null;
const price_sort = (d.price_sort || "").toLowerCase().trim();
const qa_intents = Array.isArray(d.qa_intents) ? d.qa_intents : [];

// === Entity so sánh ===
const compare_target = (d.compare_target || "").toLowerCase().trim();
const compare_with_brand = (d.compare_with_brand || "").toLowerCase().trim();
const compare_with_model = (d.compare_with_model || "").trim();

const sales_subcategory = (d.sales_subcategory || "consultation").toLowerCase().trim();
const province = (d.province || "ho-chi-minh").toLowerCase().trim();

// === Đếm SALES_LEAD turn để trigger lead capture ===
const history = (d._prev?.history) || [];
const sales_turn_count = history.filter(h => h.intent === 'SALES_LEAD').length;
const should_capture_lead = sales_turn_count >= 2;

const THACO_BRANDS = ['kia', 'mazda', 'peugeot', 'bmw', 'mini', 'thaco-truck', 'thaco-bus'];

// =========================================================
// HELPER 1: Trim markdown — chỉ giữ section H2 trong allowlist
// =========================================================
function trimMarkdown(md, allowlist, opts = {}) {
  if (!md || typeof md !== 'string') return '';
  const maxChars = opts.maxChars || 3500;
  md = md.replace(/^---[\s\S]*?---\s*/m, '');
  md = md.replace(/^>.*$/gm, '');
  md = md.replace(/!\[[^\]]*\]\([^\)]*\)/g, '');
  const parts = md.split(/^## /m);
  const intro = parts.shift() || '';
  let kept = intro.trim() + '\n';
  for (const part of parts) {
    const heading = part.split('\n')[0].toLowerCase();
    if (allowlist.some(k => heading.includes(k.toLowerCase()))) {
      kept += '\n## ' + part.trim() + '\n';
    }
  }
  if (kept.length > maxChars) kept = kept.slice(0, maxChars) + '\n...[đã rút gọn]';
  return kept.trim();
}

// =========================================================
// HELPER 1B: Extract chỉ Tóm tắt + Trang bị nổi bật phiên bản đầu (cho compare)
// =========================================================
function extractCompareMd(md) {
  if (!md || typeof md !== 'string') return '';
  md = md.replace(/^---[\s\S]*?---\s*/m, '');
  md = md.replace(/^>.*$/gm, '');
  md = md.replace(/!\[[^\]]*\]\([^\)]*\)/g, '');

  // Split theo ^## để lấy từng section H2 — tránh dùng \Z (không hỗ trợ trong JS regex,
  // bị hiểu là literal Z và với /i flag thành [Zz] → cắt sai ở chữ z trong "mazda")
  const sections = md.split(/^## /m);
  let result = '';

  // 1. Section Tóm tắt
  for (const sec of sections.slice(1)) {
    const heading = sec.split('\n')[0].toLowerCase();
    if (heading.includes('tóm tắt') || heading.includes('tom tat')) {
      result += '## ' + sec.trim() + '\n\n';
      break;
    }
  }

  // 2. Section Trang bị nổi bật → chỉ giữ phiên bản H3 đầu tiên
  for (const sec of sections.slice(1)) {
    const heading = sec.split('\n')[0].toLowerCase();
    if (heading.includes('trang bị nổi bật')) {
      const h3Parts = sec.split(/^### /m);
      if (h3Parts.length >= 2) {
        const header = '## ' + h3Parts[0].trim();
        const firstVersion = h3Parts[1].trim();
        result += `${header}\n\n### ${firstVersion}\n`;
      } else {
        result += '## ' + sec.trim() + '\n';
      }
      break;
    }
  }

  return result.trim();
}

// =========================================================
// HELPER 1C: Tính giá lăn bánh — fetch policy + compute theo seat + brand
// =========================================================
let _rollingPolicy = null;
async function calcRollingPrice(modelPrice, provinceArg, seatArg, brandArg) {
  if (!modelPrice || modelPrice <= 0) return null;
  try {
    if (!_rollingPolicy) {
      const data = await this.helpers.httpRequest({
        method: 'GET',
        url: base + 'wiki/policies/rolling-price.json',
        json: true,
        returnFullResponse: false
      });
      _rollingPolicy = (typeof data === 'string') ? JSON.parse(data) : data;
    }
    const p = _rollingPolicy;

    // 1. Province → phí trước bạ % + phí biển số
    const provinceKey = (p.registration_fee_pct[provinceArg]) ? provinceArg : 'default';
    const reg_pct = p.registration_fee_pct[provinceKey];
    const plate = p.license_plate_fee_vnd[provinceKey];
    const reg_fee = Math.round(modelPrice * reg_pct);

    // 2. Bảo hiểm vật chất theo % giá xe
    const physical_ins = Math.round(modelPrice * p.physical_insurance_pct);

    // 3. TNDS theo SỐ CHỖ NGỒI
    const seatNum = Number(seatArg || 5);
    let tnds;
    let tnds_tier;
    if (seatNum <= 5) {
      tnds = p.tnds_insurance_yr_vnd['5_seat_or_less'];
      tnds_tier = '≤5 chỗ';
    } else if (seatNum <= 7) {
      tnds = p.tnds_insurance_yr_vnd['6_to_7_seat'];
      tnds_tier = '6-7 chỗ';
    } else {
      tnds = p.tnds_insurance_yr_vnd['8_seat_or_more'];
      tnds_tier = '≥8 chỗ';
    }

    // 4. Service fee theo BRAND
    const brandKey = (brandArg || '').toLowerCase().trim();
    const service_fee = p.service_fee_vnd.by_brand[brandKey] || p.service_fee_vnd.default;

    // 5. Phí cố định
    const inspection = p.fixed_fees_vnd.inspection;
    const road_maintenance = p.fixed_fees_vnd.road_maintenance_yr;

    // 6. Tổng
    const total = modelPrice + reg_fee + plate
      + inspection + road_maintenance + tnds + service_fee
      + physical_ins;

    return {
      province_used: provinceKey,
      registration_fee_pct: reg_pct,
      seat_used: seatNum,
      tnds_tier,
      brand_used: brandKey || 'default',
      breakdown: {
        model_price: modelPrice,
        registration_fee: reg_fee,
        license_plate: plate,
        inspection,
        road_maintenance,
        tnds_insurance: tnds,
        service_fee,
        physical_insurance: physical_ins
      },
      total,
      labels: p.fee_labels_vi,
      notes: p.notes
    };
  } catch (e) {
    return { error: e.message };
  }
}

// Format helper VNĐ
function fmtVnd(n) {
  if (n === null || n === undefined) return '—';
  return Math.round(n).toLocaleString('de-DE') + ' ₫';
}

// Format calc result thành text bundle
function formatRollingPriceBundle(modelName, calc) {
  if (!calc || calc.error) return `\n[LỖI tính giá lăn bánh: ${calc?.error || 'không có giá'}]`;
  const b = calc.breakdown;
  const L = calc.labels;
  const provinceText = calc.province_used === 'ho-chi-minh' ? 'HCM' :
    calc.province_used === 'ha-noi' ? 'HN' : 'tỉnh khác';
  return `\n\n=== GIÁ LĂN BÁNH ƯỚC TÍNH ${modelName} (đăng ký ${provinceText}, ${calc.seat_used} chỗ, brand=${calc.brand_used}) ===
- ${L.model_price}: ${fmtVnd(b.model_price)}
- ${L.registration_fee} (${(calc.registration_fee_pct * 100)}%): ${fmtVnd(b.registration_fee)}
- ${L.license_plate}: ${fmtVnd(b.license_plate)}
- ${L.inspection}: ${fmtVnd(b.inspection)}
- ${L.road_maintenance}: ${fmtVnd(b.road_maintenance)}
- ${L.tnds_insurance} [${calc.tnds_tier}]: ${fmtVnd(b.tnds_insurance)}
- ${L.service_fee} [brand ${calc.brand_used}]: ${fmtVnd(b.service_fee)}
- ${L.physical_insurance}: ${fmtVnd(b.physical_insurance)}
- **TỔNG GIÁ LĂN BÁNH ƯỚC TÍNH: ${fmtVnd(calc.total)}**

GHI CHÚ:
${calc.notes.map(n => '- ' + n).join('\n')}`;
}

// =========================================================
// HELPER 2: Load FAQ filtered by model + intent
// =========================================================
let _faqCatalog = null;
async function loadFaqFiltered(modelSlug, intents, maxQ = 5) {
  if (!modelSlug) return '';
  try {
    if (!_faqCatalog) {
      const cat = await this.helpers.httpRequest({
        method: 'GET',
        url: base + 'wiki/faq/catalog.json',
        json: true, returnFullResponse: false
      });
      _faqCatalog = (typeof cat === 'string' ? JSON.parse(cat) : cat);
    }
    let qs = (_faqCatalog.questions || []).filter(q => q.model_slug === modelSlug);
    if (!qs.length) return '';
    if (intents && intents.length) {
      const matched = qs.filter(q => q.intents.some(i => intents.includes(i)));
      if (matched.length) qs = matched;
    }
    qs = qs.slice(0, maxQ);
    return '\n\n=== FAQ ĐÃ FILTER (model=' + modelSlug
      + ', intents=[' + (intents || []).join(',') + '], '
      + qs.length + ' câu) ===\n'
      + qs.map(q =>
        `\n**Q${q.qno}: ${q.question}**\n_intents: ${q.intents.join(', ')}_\n${q.answer}`
      ).join('\n\n---\n');
  } catch (e) {
    return `\n[FAQ LỖI: ${e.message}]`;
  }
}

// =========================================================
// PROFILES
// =========================================================
const PROFILES = {
  detail: {
    model: ['tóm tắt', 'phiên bản', 'màu sắc', 'khuyến mãi', 'trang bị nổi bật'],
    faq_max_q: 5,
    model_max_chars: 3500
  },
  shortlist_small: {
    model: ['tóm tắt', 'phiên bản', 'khuyến mãi'],
    faq_max_q: 3,
    model_max_chars: 2000
  },
  shortlist_big: {},
  compare_internal: {
    model: ['tóm tắt', 'phiên bản', 'thông số', 'trang bị nổi bật', 'khuyến mãi'],
    faq_max_q: 3,
    model_max_chars: 3500
  },
  compare_external: {
    model: ['tóm tắt', 'phiên bản', 'trang bị nổi bật'],
    faq_max_q: 8,
    model_max_chars: 3500
  },
  // SUB-MODES of SALES_LEAD
  sub_consultation: {
    model: ['tóm tắt', 'phiên bản', 'màu sắc', 'khuyến mãi'],
    faq_max_q: 5,
    model_max_chars: 2500
  },
  sub_pricing_finance: {
    model: ['tóm tắt', 'phiên bản', 'khuyến mãi'],
    faq_max_q: 3,
    model_max_chars: 2000
  },
  sub_tech_specs: {
    model: ['tóm tắt', 'thông số', 'trang bị nổi bật', 'khác biệt', 'màu sắc'],
    faq_max_q: 4,
    model_max_chars: 4500
  },
  sub_close_deal: {
    model: ['tóm tắt'],
    faq_max_q: 0,
    model_max_chars: 800
  }
};

let mode = "unknown";
let files_used = [];
let shortlist = [];
let all_matches = [];
let bundle = '';

function fullSlug(slug, brandHint) {
  if (!slug) return '';
  if (brandHint && !slug.startsWith(brandHint)) return `${brandHint}-${slug}`;
  return slug;
}

// =========================================================
// MODE ROUTING
// =========================================================
if (model_slug && compare_target) {
  mode = "compare_internal";
  const slug_a = fullSlug(model_slug, brand);
  const slug_b = compare_target;
  files_used.push(`wiki/models/${slug_a}.md`);
  files_used.push(`wiki/models/${slug_b}.md`);

} else if (model_slug && compare_with_brand && !THACO_BRANDS.includes(compare_with_brand)) {
  mode = "compare_external";
  const slug_a = fullSlug(model_slug, brand);
  files_used.push(`wiki/models/${slug_a}.md`);

} else if (model_slug) {
  mode = "detail";
  const slug_a = fullSlug(model_slug, brand);
  files_used.push(`wiki/models/${slug_a}.md`);

} else if (brand || car_type || seat_min || fuel || budget_max) {
  let catalog;
  try {
    const raw = await this.helpers.httpRequest({
      method: 'GET',
      url: base + 'wiki/models/catalog.json',
      json: true, returnFullResponse: false
    });
    catalog = (typeof raw === 'string' ? JSON.parse(raw) : raw).models || [];
  } catch (e) { catalog = []; }

  let filtered = catalog.filter(m => {
    if (brand && (m.brand || "").toLowerCase() !== brand) return false;
    if (car_type && !(m.car_type || "").toLowerCase().includes(car_type)) return false;
    if (seat_min && Number(m.seat || 0) < seat_min) return false;
    if (fuel) {
      const f = (m.fuel || "").toLowerCase();
      const fuelMap = {
        'dầu': ['dầu', 'diesel'],
        'xăng': ['xăng', 'petrol', 'gasoline'],
        'hybrid': ['hybrid', 'hev'],
        'phev': ['phev', 'hybrid'],
        'ev': ['ev', 'điện']
      };
      if (!(fuelMap[fuel] || [fuel]).some(a => f.includes(a))) return false;
    }
    if (budget_max) {
      const p = Number(m.price_min_vnd || 0);
      const upper = budget_max * 1.05;
      const lower = budget_max > 1_000_000_000 ? budget_max * 0.65 : 0;
      if (p > upper) return false;
      if (lower && p < lower) return false;
    }
    return true;
  });

  if (budget_max) {
    filtered.sort((a, b) =>
      Math.abs(Number(a.price_min_vnd || 0) - budget_max) -
      Math.abs(Number(b.price_min_vnd || 0) - budget_max)
    );
  } else if (price_sort === 'desc') {
    filtered.sort((a, b) => (b.price_max_vnd || b.price_min_vnd || 0) - (a.price_max_vnd || a.price_min_vnd || 0));
  } else {
    filtered.sort((a, b) => (a.price_min_vnd || 0) - (b.price_min_vnd || 0));
  }

  all_matches = filtered.slice();
  shortlist = filtered.slice(0, price_sort ? 3 : 5);

  if (shortlist.length === 0) {
    mode = "ask_more";
    bundle = `[KHÔNG có model nào khớp filter: brand=${brand}, type=${car_type}, seat>=${seat_min}, fuel=${fuel}, budget=${budget_max}]\nGợi ý cho AI: xin lỗi khách, đề xuất nới 1 tiêu chí.`;
  } else {
    mode = shortlist.length <= 2 ? "shortlist_small" : "shortlist_big";
    bundle = `=== SHORTLIST (${shortlist.length} xe khớp tiêu chí, total ${all_matches.length}) ===\n`
      + shortlist.map(m =>
        `- ${m.name} (${m.car_type}${m.body_style_display ? '/' + m.body_style_display : ''}, ${m.seat} chỗ, ${m.fuel}) — Giá từ ${(m.price_min_vnd / 1e6).toFixed(0)} triệu — slug: ${m.slug}`
      ).join('\n');
    if (mode === "shortlist_small") {
      for (const m of shortlist) files_used.push(m.url);
    }
  }

} else {
  mode = "ask_more";
  bundle = "[Khách chưa đủ thông tin để filter. AI cần hỏi: thương hiệu? loại xe? số chỗ? ngân sách?]";
}

// =========================================================
// PROFILE OVERRIDE THEO SUB-CATEGORY
// =========================================================
let profile = { ...(PROFILES[mode] || PROFILES.detail) };

if ((mode === "detail" || mode === "shortlist_small") && d.category === "SALES_LEAD") {
  const subProfileKey = `sub_${sales_subcategory}`;
  if (PROFILES[subProfileKey]) {
    Object.assign(profile, PROFILES[subProfileKey]);
    mode = mode + "_" + sales_subcategory;
  }
}

// =========================================================
// FETCH model MD + TRIM
// =========================================================
for (const f of files_used) {
  try {
    const data = await this.helpers.httpRequest({
      method: 'GET', url: base + f, returnFullResponse: false
    });
    const raw = typeof data === 'string' ? data : JSON.stringify(data);
    let trimmed;
    if (mode === "compare_external") {
      // So sánh với đối thủ ngoài THACO → chỉ có 1 file model THACO,
      // cần đủ chỗ cho Tóm tắt + Phiên bản 1 đầy đủ của Trang bị nổi bật.
      trimmed = extractCompareMd(raw);
      if (trimmed.length > 4500) trimmed = trimmed.slice(0, 4500) + '\n...[đã rút gọn]';
    } else {
      // Bao gồm compare_internal — dùng allowlist từ PROFILES.compare_internal
      // (tóm tắt, phiên bản, thông số, trang bị nổi bật, khuyến mãi)
      trimmed = trimMarkdown(
        raw,
        profile.model || ['tóm tắt', 'phiên bản', 'khuyến mãi'],
        { maxChars: profile.model_max_chars || 3000 }
      );
    }
    bundle += `\n\n=== FILE: ${f} ===\n${trimmed}`;
  } catch (e) { /* skip 404 */ }
}

// =========================================================
// LOAD FAQ FILTERED
// =========================================================
if (mode.startsWith("detail")) {
  const slug_a = fullSlug(model_slug, brand);
  bundle += await loadFaqFiltered.call(this, slug_a, qa_intents, profile.faq_max_q);
} else if (mode.startsWith("shortlist_small")) {
  for (const m of shortlist) {
    bundle += await loadFaqFiltered.call(this, m.slug, qa_intents, profile.faq_max_q);
  }
} else if (mode === "compare_internal") {
  const slug_a = fullSlug(model_slug, brand);
  bundle += await loadFaqFiltered.call(this, slug_a, ["SO_SANH"], profile.faq_max_q);
  bundle += await loadFaqFiltered.call(this, compare_target, ["SO_SANH"], profile.faq_max_q);
  bundle += `\n\n=== ĐANG SO SÁNH NỘI BỘ THACO ===\nXe A: ${slug_a}\nXe B: ${compare_target}\nGợi ý: trình bày bullet trung thực, không thiên vị.`;
} else if (mode === "compare_external") {
  const slug_a = fullSlug(model_slug, brand);
  bundle += await loadFaqFiltered.call(this, slug_a, ["SO_SANH"], profile.faq_max_q);
  bundle += `\n\n=== ĐỐI THỦ KHÁCH NHẮC (NGOÀI THACO) ===\nBrand đối thủ: ${compare_with_brand}\nModel đối thủ: ${compare_with_model || '(không rõ)'}\nXe THACO đang tư vấn: ${slug_a}\nGợi ý: nêu điểm MẠNH của xe THACO bằng số liệu cụ thể từ FAQ. KHÔNG nói xấu đối thủ.`;
}

// =========================================================
// ROLLING PRICE CALC — chạy khi sub_pricing_finance
// → Tính bằng JS theo seat + brand thực, AI chỉ format
// =========================================================
if (sales_subcategory === "pricing_finance" && (mode.startsWith("detail") || mode.startsWith("shortlist_small"))) {
  // Lấy danh sách xe + giá min + seat + brand để tính
  let targets = [];

  // Cần load catalog để lấy đủ thông tin (seat, brand, price)
  let _catalog = [];
  try {
    const raw = await this.helpers.httpRequest({
      method: 'GET', url: base + 'wiki/models/catalog.json',
      json: true, returnFullResponse: false
    });
    _catalog = (typeof raw === 'string' ? JSON.parse(raw) : raw).models || [];
  } catch (e) { }

  if (mode.startsWith("detail")) {
    const slug_a = fullSlug(model_slug, brand);
    const m = _catalog.find(x => x.slug === slug_a);
    if (m) targets.push({
      name: m.name,
      price: m.price_min_vnd,
      seat: m.seat,
      brand: m.brand
    });
  } else if (mode.startsWith("shortlist_small")) {
    targets = shortlist.slice(0, 2).map(m => ({
      name: m.name,
      price: m.price_min_vnd,
      seat: m.seat,
      brand: m.brand
    }));
  }

  for (const t of targets) {
    if (!t.price) continue;
    const calc = await calcRollingPrice.call(this, t.price, province, t.seat, t.brand);
    bundle += formatRollingPriceBundle(t.name, calc);
  }
}

console.log('BUNDLE LENGTH =', bundle.length);
console.log('BUNDLE TAIL =', bundle.slice(-300));

return [{
  json: {
    ...d,
    mode,
    shortlist,
    all_matches,
    files_used,
    qa_intents,
    sales_subcategory,
    sales_turn_count,
    should_capture_lead,
    province_used: province,
    price_sort,
    context_bundle: bundle,
    bundle_size: bundle.length
  }
}];

// NORMALIZE ENTITIES — Validate AI output against vocab.json from GitHub
const VOCAB_URL = 'https://raw.githubusercontent.com/Meeyana/thacoauto-lib/main/wiki/models/vocab.json';

let vocab;
try {
  vocab = await this.helpers.httpRequest({ method: 'GET', url: VOCAB_URL, json: true, returnFullResponse: false });
  if (typeof vocab === 'string') vocab = JSON.parse(vocab);
} catch (e) {
  // Fail-open: nếu vocab không tải được thì pass-through (đừng chặn cả pipeline)
  return [{ json: { ...$input.first().json, _vocab_error: e.message } }];
}

const d = $input.first().json;

// Helper: lookup giá trị qua synonym map → trả canonical key, hoặc null
function lookupSynonym(value, dict) {
  if (!value) return null;
  const v = value.toString().toLowerCase().trim();
  if (!dict || !dict.synonyms) return null;

  // 1. Direct match canonical key
  for (const canon of Object.keys(dict.synonyms)) {
    if (canon.toLowerCase() === v) return canon;
  }
  // 2. Match trong list synonym (exact)
  for (const [canon, syns] of Object.entries(dict.synonyms)) {
    if (syns.some(s => s.toLowerCase() === v)) return canon;
  }
  // 3. Partial match (substring) — nới lỏng cho text dài
  for (const [canon, syns] of Object.entries(dict.synonyms)) {
    if (syns.some(s => v.includes(s.toLowerCase()) || s.toLowerCase().includes(v))) return canon;
  }
  return null;
}

// Helper: validate model_slug có trong list không
function validateSlug(slug, validList) {
  if (!slug) return null;
  const s = slug.toString().toLowerCase().trim().replace(/\s+/g, '-');

  // 1. Exact match
  if (validList.includes(s)) return s;

  // 2. Thử ghép brand prefix: "carens" + brand="kia" → "kia-carens"
  if (d.brand) {
    const guess = `${d.brand.toLowerCase()}-${s}`;
    if (validList.includes(guess)) return guess;
  }

  // 3. Partial match có dash boundary: "cx-3" → "mazda-cx-3"
  const candidates = validList.filter(v => {
    if (d.brand && !v.startsWith(d.brand.toLowerCase() + '-')) return false;
    return v.endsWith('-' + s) || v === s || v.includes('-' + s + '-');
  });
  if (candidates.length === 1) return candidates[0];
  if (candidates.length > 1) {
    return candidates.sort((a, b) => a.length - b.length)[0];
  }

  // 4. ⭐ MỚI — Strip-dash compare: "cx3" → "mazdacx3" → so với "mazda-cx-3" → "mazdacx3" ✅
  //    Áp dụng cho TẤT CẢ slug viết liền không dash (cx3, cx30, mx5, k5...)
  const stripDash = (x) => x.replace(/-/g, '');
  const sStripped = stripDash(s);

  const fuzzyCandidates = validList.filter(v => {
    if (d.brand && !v.startsWith(d.brand.toLowerCase() + '-')) return false;
    const vStripped = stripDash(v);
    // EXACT strip match: "cx3" === "mazdacx3"? Không, nhưng endsWith mới đúng
    // endsWith match: "mazdacx3".endsWith("cx3") ✅; "mazdacx30".endsWith("cx3") ❌
    return vStripped === sStripped || vStripped.endsWith(sStripped);
  });

  if (fuzzyCandidates.length === 1) return fuzzyCandidates[0];
  if (fuzzyCandidates.length > 1) {
    // Ưu tiên slug ngắn hơn (cụ thể hơn): "cx3" → "mazda-cx-3" thắng "mazda-cx-30"
    return fuzzyCandidates.sort((a, b) => a.length - b.length)[0];
  }

  return null;
}


// Validate seat_min: phải là số nguyên trong canonical
function validateSeat(value, allowed) {
  if (value === null || value === undefined || value === '') return null;
  const n = Number(value);
  if (!Number.isFinite(n)) return null;
  // Cho phép giá trị nhỏ hơn min canonical (vd khách hỏi "4 chỗ" nhưng catalog chỉ có từ 5)
  // Nhưng giới hạn trong khoảng hợp lý 2-16
  return (n >= 2 && n <= 16) ? n : null;
}

// Normalize tất cả entity
const normalized = {
  brand:      lookupSynonym(d.brand, vocab.brand),
  car_type:   lookupSynonym(d.car_type, vocab.car_type),
  fuel:       lookupSynonym(d.fuel, vocab.fuel),
  use_case:   lookupSynonym(d.use_case, vocab.use_case),
  seat_min:   validateSeat(d.seat_min, vocab.seat?.canonical || []),
  model_slug: validateSlug(d.model_slug, vocab.model_slugs || []),
  compare_target: validateSlug(d.compare_target, vocab.model_slugs || []),
};

// Track giá trị AI bịa (để review & bổ sung synonym sau)
const unknown = {};
for (const [k, originalRaw] of Object.entries({
  brand: d.brand, car_type: d.car_type, fuel: d.fuel,
  use_case: d.use_case, model_slug: d.model_slug
})) {
  if (originalRaw && !normalized[k]) {
    unknown[k] = originalRaw;
  }
}

return [{
  json: {
    ...d,
    ...normalized,
    budget_max: d.budget_max ? Number(d.budget_max) : null,  // numeric, không cần normalize
    _unknown: Object.keys(unknown).length ? unknown : null,
    _normalized_at: new Date().toISOString()
  }
}];

const input = items[0].json;
let rawText = input.output || input.text || input.response ||
              (input.content?.parts?.[0]?.text) || (input.message?.content) || "";

const router = $('xu_ly_category').first().json;

try {
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error("Không tìm thấy JSON");
  const p = JSON.parse(jsonMatch[0]);
  return [{
    json: {
      category: router.category,
      province: (p.province || "").toLowerCase().trim(),
      showroom_name: (p.showroom_name || "").trim(),
      brand: (p.brand || router.brand || "").toLowerCase().trim(),
      status: true
    }
  }];
} catch (e) {
  return [{
    json: {
      category: router.category,
      province: "", showroom_name: "", brand: router.brand || "",
      status: false,
      _error: e.message,
      _raw_debug: rawText.substring(0, 200)
    }
  }];
}

// DEALER LOOKUP — 5 mode:
//  1. area_overview        → khách hỏi tên KHU VỰC (PMH, An Sương...) → liệt kê TẤT CẢ showroom + tổng quan brand
//  2. specific_found       → khách hỏi đích danh 1 showroom → trả info chi tiết
//  3. specific_not_found   → match 0 showroom
//  4. province_link        → khách hỏi chung theo tỉnh → trả URL
//  5. ask_province         → khách chưa nói gì → hỏi khu vực
const d = $input.first().json;
const base = 'https://raw.githubusercontent.com/Meeyana/thacoauto-lib/main/';

const province      = (d.province || "").toLowerCase().trim();
const showroom_name = (d.showroom_name || "").toLowerCase().trim();
const brand         = (d.brand || "").toLowerCase().trim();

let mode = "ask_province";
let bundle = '';
let matched_showrooms = [];
let province_url = null;

try {
  // ============================================
  // MODE: KHÁCH HỎI ĐÍCH DANH SHOWROOM hoặc KHU VỰC
  // ============================================
  if (showroom_name) {
    const cat = await this.helpers.httpRequest({
      method: 'GET',
      url: base + 'wiki/dealers/catalog.json',
      json: true,
      returnFullResponse: false
    });
    const data = (typeof cat === 'string') ? JSON.parse(cat) : cat;

    // Helper: chuẩn hoá string (bỏ dấu cách thừa, lowercase)
function norm(s) {
  return (s || "").toLowerCase().trim().replace(/\s+/g, ' ');
}

// Helper: tách thành tokens (theo word boundary, giữ tiếng Việt có dấu)
function tokens(s) {
  return norm(s).split(/[\s\-,]+/).filter(Boolean);
}

// Helper: cho điểm match giữa title và query
function scoreMatch(title, query) {
  const t = norm(title);
  const q = norm(query);
  if (!t || !q) return 0;

  // 100: exact match
  if (t === q) return 100;

  // 80: title chứa nguyên cụm query (bao quanh bởi khoảng trắng / đầu / cuối)
  //     → đảm bảo "phú mỹ hưng" KHÔNG match title chỉ chứa "phú mỹ"
  const qPattern = new RegExp(`(^|\\s)${q.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}(\\s|$)`);
  if (qPattern.test(t)) return 80;

  // 60: query chứa nguyên title (cho case khách gõ dài hơn title, vd "showroom BMW Sala" vs title "BMW Sala")
  const tPattern = new RegExp(`(^|\\s)${t.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}(\\s|$)`);
  if (tPattern.test(q)) return 60;

  // 40: tất cả token của query xuất hiện trong title (any order, exact word)
  const qTok = tokens(q);
  const tTokSet = new Set(tokens(t));
  if (qTok.length && qTok.every(w => tTokSet.has(w))) return 40;

  return 0;
}

// Score toàn bộ catalog
const scored = (data.showrooms || [])
  .map(s => ({ s, score: scoreMatch(s.title, showroom_name) }))
  .filter(x => x.score > 0)
  .sort((a, b) => b.score - a.score);

// CHỈ GIỮ điểm cao nhất → loại các match yếu hơn
let matches = [];
if (scored.length) {
  const bestScore = scored[0].score;
  matches = scored.filter(x => x.score === bestScore).map(x => x.s);
}


    // Nếu khách có nói brand cụ thể → narrow xuống brand đó
    if (brand && matches.length > 1) {
      const filtered = matches.filter(s =>
        (s.brand_slugs || []).some(b => b === brand || b.includes(brand))
      );
      // Chỉ apply filter nếu vẫn còn match (tránh ra rỗng)
      if (filtered.length) matches = filtered;
    }

    matched_showrooms = matches;

    if (matches.length === 0) {
      mode = "specific_not_found";
      bundle = `[KHÔNG tìm thấy showroom "${d.showroom_name}" trong hệ thống.
Gợi ý cho AI: xin lỗi khách, đề xuất gọi hotline 1900 56 5499.]`;

    } else if (matches.length === 1) {
      // 1 showroom đích danh → trả chi tiết đầy đủ
      mode = "specific_found";
      const f = matches[0];
      bundle = `=== SHOWROOM: ${f.title} ===
- Thương hiệu: ${f.brands.join(', ')}
- 📍 Địa chỉ: ${f.address.full}
- 📞 Bán hàng: ${f.phone_sale || '—'}
- 📞 Dịch vụ: ${f.phone_service || '—'}
- 🏷 Dịch vụ cung cấp: ${f.services.join(', ')}
- 🗺 Maps: ${f.map_url || '—'}
- 🌐 Website: ${f.website || '—'}`;

    } else {
      // Nhiều showroom cùng khu vực → tổng quan
      mode = "area_overview";

      // Tổng hợp brand của cả khu vực (unique)
      const allBrands = [...new Set(matches.flatMap(s => s.brands || []))].sort();
      // Tên khu vực: lấy phần chung trong title (vd "Phú Mỹ Hưng")
      const areaName = d.showroom_name;
      // Địa chỉ chung: lấy phường + tỉnh từ showroom đầu (thường giống nhau)
      const sampleAddr = matches[0].address || {};
      const ward = sampleAddr.ward ? `Phường ${sampleAddr.ward}` : '';
      const city = sampleAddr.province || '';

      bundle = `=== TỔNG QUAN KHU VỰC: ${areaName.toUpperCase()} ===
- Vị trí: ${[ward, city].filter(Boolean).join(', ') || '—'}
- Số showroom trong khu vực: ${matches.length}
- Tất cả thương hiệu có mặt: ${allBrands.join(', ')}

=== CHI TIẾT TỪNG SHOWROOM ===
${matches.map(s => `
**${s.title}**
- Thương hiệu: ${s.brands.join(', ')}
- 📍 ${s.address.full}
- 📞 Bán hàng: ${s.phone_sale || '—'} | Dịch vụ: ${s.phone_service || '—'}
- 🏷 ${s.services.join(', ')}
- 🗺 ${s.map_url || '—'}`).join('\n\n---\n')}`;
    }

  // ============================================
  // MODE: KHÁCH HỎI CHUNG, CÓ TỈNH/THÀNH
  // ============================================
  } else if (province) {
    const cat = await this.helpers.httpRequest({
      method: 'GET',
      url: base + 'wiki/dealers/catalog.json',
      json: true,
      returnFullResponse: false
    });
    const data = (typeof cat === 'string') ? JSON.parse(cat) : cat;
    province_url = (data.province_urls || {})[province] || null;

    if (province_url) {
      mode = "province_link";
      bundle = `=== KHÁCH HỎI CHUNG SHOWROOM TẠI: ${province} ===
URL chính thức: ${province_url}
Brand quan tâm: ${brand || 'tất cả'}`;
    } else {
      mode = "province_no_link";
      bundle = `[Chưa có URL website cho tỉnh "${province}".
Gợi ý cho AI: xin lỗi và mời khách gọi hotline 1900 56 5499.]`;
    }

  // ============================================
  // MODE: CHƯA CÓ THÔNG TIN — HỎI LẠI
  // ============================================
  } else {
    mode = "ask_province";
    bundle = `[Khách hỏi chung "showroom" nhưng chưa nói khu vực hay tên cụ thể.
Gợi ý cho AI: hỏi lịch sự "Anh/Chị đang ở tỉnh/thành hoặc khu vực nào ạ?"]`;
  }

} catch (e) {
  bundle = `[LỖI: ${e.message}. Hướng dẫn khách gọi hotline 1900 56 5499.]`;
  mode = "error";
}

return [{
  json: {
    ...d,
    mode,
    matched_showrooms,
    matched_count: matched_showrooms.length,
    province_url,
    context_bundle: bundle
  }
}];

